{
  "inputShape": "{ limit: z.number().int().optional().describe("Maximum number of pets to return"), tags: z.array(z.string()).optional() }",
  "handlerBody": "  const res = await ctx.http.request({
    method: "GET",
    path: "/pets",
    query: { limit: args.limit, tags: args.tags },
  });
  return {
    content: [{ type: "text", text: JSON.stringify(res.data, null, 2) }],
    isError: res.status >= 400,
  };"
}
